def build_item_index():
    STORAGE_ITEMS_INDEX.clear()

    for activity_name, activity in ACTIVITIES.items():
        for item in activity["loot"]:
            STORAGE_ITEMS_INDEX[item["id"]] = {
                "activity": activity_name,
                **item
            }

